/*                                                                                                                    */
/*                                          Analog to Digital Converter (ADC)                                         */
/*                                                                                                                    */
/**********************************************************************************************************************/
#define ADC_INST_IN_COMMON_COUNT (1U) /*!< Number of ADC instances within ADC common instance
                                           Note: maximum number for all common instances (in case of multiple ADC
                                                 common instances, some may encompass less ADC instances). */

/* *************************************  Bit definition for ADC_ISR register  ************************************** */
#define ADC_ISR_ADRDY_Pos        (0U)
#define ADC_ISR_ADRDY_Msk        (0x1UL << ADC_ISR_ADRDY_Pos)          /*!< 0x00000001 */
#define ADC_ISR_ADRDY            ADC_ISR_ADRDY_Msk                     /*!< ADC ready */
#define ADC_ISR_EOSMP_Pos        (1U)
#define ADC_ISR_EOSMP_Msk        (0x1UL << ADC_ISR_EOSMP_Pos)          /*!< 0x00000002 */
#define ADC_ISR_EOSMP            ADC_ISR_EOSMP_Msk                     /*!< End of sampling flag */
#define ADC_ISR_EOC_Pos          (2U)
#define ADC_ISR_EOC_Msk          (0x1UL << ADC_ISR_EOC_Pos)            /*!< 0x00000004 */
#define ADC_ISR_EOC              ADC_ISR_EOC_Msk                       /*!< End of conversion flag */
#define ADC_ISR_EOS_Pos          (3U)
#define ADC_ISR_EOS_Msk          (0x1UL << ADC_ISR_EOS_Pos)            /*!< 0x00000008 */
#define ADC_ISR_EOS              ADC_ISR_EOS_Msk                       /*!< End of regular sequence flag */
#define ADC_ISR_OVR_Pos          (4U)
#define ADC_ISR_OVR_Msk          (0x1UL << ADC_ISR_OVR_Pos)            /*!< 0x00000010 */
#define ADC_ISR_OVR              ADC_ISR_OVR_Msk                       /*!< ADC overrun */
#define ADC_ISR_JEOC_Pos         (5U)
#define ADC_ISR_JEOC_Msk         (0x1UL << ADC_ISR_JEOC_Pos)           /*!< 0x00000020 */
#define ADC_ISR_JEOC             ADC_ISR_JEOC_Msk                      /*!< Injected channel end of conversion flag */
#define ADC_ISR_JEOS_Pos         (6U)
#define ADC_ISR_JEOS_Msk         (0x1UL << ADC_ISR_JEOS_Pos)           /*!< 0x00000040 */
#define ADC_ISR_JEOS             ADC_ISR_JEOS_Msk                      /*!< Injected channel end of sequence flag */
#define ADC_ISR_AWD1_Pos         (7U)
#define ADC_ISR_AWD1_Msk         (0x1UL << ADC_ISR_AWD1_Pos)           /*!< 0x00000080 */
#define ADC_ISR_AWD1             ADC_ISR_AWD1_Msk                      /*!< Analog watchdog 1 flag */
#define ADC_ISR_AWD2_Pos         (8U)
#define ADC_ISR_AWD2_Msk         (0x1UL << ADC_ISR_AWD2_Pos)           /*!< 0x00000100 */
#define ADC_ISR_AWD2             ADC_ISR_AWD2_Msk                      /*!< Analog watchdog 2 flag */
#define ADC_ISR_AWD3_Pos         (9U)
#define ADC_ISR_AWD3_Msk         (0x1UL << ADC_ISR_AWD3_Pos)           /*!< 0x00000200 */
#define ADC_ISR_AWD3             ADC_ISR_AWD3_Msk                      /*!< Analog watchdog 3 flag */
#define ADC_ISR_LDORDY_Pos       (12U)
#define ADC_ISR_LDORDY_Msk       (0x1UL << ADC_ISR_LDORDY_Pos)         /*!< 0x00001000 */
#define ADC_ISR_LDORDY           ADC_ISR_LDORDY_Msk                    /*!< ADC internal voltage regulator output ready
                                                                            flag */

/* *************************************  Bit definition for ADC_IER register  ************************************** */
#define ADC_IER_ADRDYIE_Pos      (0U)
#define ADC_IER_ADRDYIE_Msk      (0x1UL << ADC_IER_ADRDYIE_Pos)        /*!< 0x00000001 */
#define ADC_IER_ADRDYIE          ADC_IER_ADRDYIE_Msk                   /*!< ADC ready interrupt enable */
#define ADC_IER_EOSMPIE_Pos      (1U)
#define ADC_IER_EOSMPIE_Msk      (0x1UL << ADC_IER_EOSMPIE_Pos)        /*!< 0x00000002 */
#define ADC_IER_EOSMPIE          ADC_IER_EOSMPIE_Msk                   /*!< End of sampling flag interrupt enable for
                                                                            regular conversions */
#define ADC_IER_EOCIE_Pos        (2U)
#define ADC_IER_EOCIE_Msk        (0x1UL << ADC_IER_EOCIE_Pos)          /*!< 0x00000004 */
#define ADC_IER_EOCIE            ADC_IER_EOCIE_Msk                     /*!< End of regular conversion interrupt enable
                                                                            */
#define ADC_IER_EOSIE_Pos        (3U)
#define ADC_IER_EOSIE_Msk        (0x1UL << ADC_IER_EOSIE_Pos)          /*!< 0x00000008 */
#define ADC_IER_EOSIE            ADC_IER_EOSIE_Msk                     /*!< End of regular sequence of conversions
                                                                            interrupt enable */
#define ADC_IER_OVRIE_Pos        (4U)
#define ADC_IER_OVRIE_Msk        (0x1UL << ADC_IER_OVRIE_Pos)          /*!< 0x00000010 */
#define ADC_IER_OVRIE            ADC_IER_OVRIE_Msk                     /*!< Overrun interrupt enable */
#define ADC_IER_JEOCIE_Pos       (5U)
#define ADC_IER_JEOCIE_Msk       (0x1UL << ADC_IER_JEOCIE_Pos)         /*!< 0x00000020 */
#define ADC_IER_JEOCIE           ADC_IER_JEOCIE_Msk                    /*!< End of injected conversion interrupt enable
                                                                            */
#define ADC_IER_JEOSIE_Pos       (6U)
#define ADC_IER_JEOSIE_Msk       (0x1UL << ADC_IER_JEOSIE_Pos)         /*!< 0x00000040 */
#define ADC_IER_JEOSIE           ADC_IER_JEOSIE_Msk                    /*!< End of injected sequence of conversions
                                                                            interrupt enable */
#define ADC_IER_AWD1IE_Pos       (7U)
#define ADC_IER_AWD1IE_Msk       (0x1UL << ADC_IER_AWD1IE_Pos)         /*!< 0x00000080 */
#define ADC_IER_AWD1IE           ADC_IER_AWD1IE_Msk                    /*!< Analog watchdog 1 interrupt enable */
#define ADC_IER_AWD2IE_Pos       (8U)
#define ADC_IER_AWD2IE_Msk       (0x1UL << ADC_IER_AWD2IE_Pos)         /*!< 0x00000100 */
#define ADC_IER_AWD2IE           ADC_IER_AWD2IE_Msk                    /*!< Analog watchdog 2 interrupt enable */
#define ADC_IER_AWD3IE_Pos       (9U)
#define ADC_IER_AWD3IE_Msk       (0x1UL << ADC_IER_AWD3IE_Pos)         /*!< 0x00000200 */
#define ADC_IER_AWD3IE           ADC_IER_AWD3IE_Msk                    /*!< Analog watchdog 3 interrupt enable */
#define ADC_IER_LDORDYIE_Pos     (12U)
#define ADC_IER_LDORDYIE_Msk     (0x1UL << ADC_IER_LDORDYIE_Pos)       /*!< 0x00001000 */
#define ADC_IER_LDORDYIE         ADC_IER_LDORDYIE_Msk                  /*!< ADC internal voltage regulator interrupt
                                                                            enable */

/* **************************************  Bit definition for ADC_CR register  ************************************** */
#define ADC_CR_ADEN_Pos          (0U)
#define ADC_CR_ADEN_Msk          (0x1UL << ADC_CR_ADEN_Pos)            /*!< 0x00000001 */
#define ADC_CR_ADEN              ADC_CR_ADEN_Msk                       /*!< ADC enable control */
#define ADC_CR_ADDIS_Pos         (1U)
#define ADC_CR_ADDIS_Msk         (0x1UL << ADC_CR_ADDIS_Pos)           /*!< 0x00000002 */
#define ADC_CR_ADDIS             ADC_CR_ADDIS_Msk                      /*!< ADC disable command */
#define ADC_CR_ADSTART_Pos       (2U)
#define ADC_CR_ADSTART_Msk       (0x1UL << ADC_CR_ADSTART_Pos)         /*!< 0x00000004 */
#define ADC_CR_ADSTART           ADC_CR_ADSTART_Msk                    /*!< ADC start of regular conversion */
#define ADC_CR_JADSTART_Pos      (3U)
#define ADC_CR_JADSTART_Msk      (0x1UL << ADC_CR_JADSTART_Pos)        /*!< 0x00000008 */
#define ADC_CR_JADSTART          ADC_CR_JADSTART_Msk                   /*!< ADC start of injected conversion */
#define ADC_CR_ADSTP_Pos         (4U)
#define ADC_CR_ADSTP_Msk         (0x1UL << ADC_CR_ADSTP_Pos)           /*!< 0x00000010 */
#define ADC_CR_ADSTP             ADC_CR_ADSTP_Msk                      /*!< ADC stop of regular conversion command */
#define ADC_CR_JADSTP_Pos        (5U)
#define ADC_CR_JADSTP_Msk        (0x1UL << ADC_CR_JADSTP_Pos)          /*!< 0x00000020 */
#define ADC_CR_JADSTP            ADC_CR_JADSTP_Msk                     /*!< ADC stop of injected conversion command */
